  if (!proofPoints.length) proofPoints.push('Mindestens ein Proof Point aus Evidence-Packages erforderlich.');

  if (platformLabel === 'linkedin') {
    return {
      core_problem: coreProblem,
      proof_points: proofPoints,
      insight_angles: lines.slice(6, 10).map((line) => shortText(line, 140)),
      hook_options: lines.slice(10, 13).map((line) => shortText(line, 120)),
      cta_options: lines.slice(13, 16).map((line) => shortText(line, 120)),
