function extractJsonCandidate(rawText) {
  if (typeof rawText !== 'string') throw new Error('Model output is not a string');
  const fenced = rawText.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const text = (fenced ? fenced[1] : rawText).trim();
  try { return JSON.parse(text); } catch {}
  const objStart = text.indexOf('{');
  const arrStart = text.indexOf('[');
  const starts = [objStart, arrStart].filter((v) => v >= 0);
  if (!starts.length) throw new Error('No JSON start found');
  const start = Math.min(...starts);
  const openChar = text[start];
  const closeChar = openChar === '{' ? '}' : ']';
  let depth = 0, inString = false, escaped = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === '"') inString = false;
      continue;
    }
    if (ch === '"') { inString = true; continue; }
    if (ch === openChar) depth += 1;
    if (ch === closeChar) {
      depth -= 1;
      if (depth === 0) return JSON.parse(text.slice(start, i + 1));
    }
  }
  throw new Error('Could not extract valid JSON payload');
}

async function callOllamaRaw(systemPrompt, userPrompt, options = {}) {
  const temperature = Number.isFinite(Number(options.temperature)) ? Number(options.temperature) : 0.3;
  const numPredict = Number.isFinite(Number(options.num_predict)) ? Number(options.num_predict) : 180;
  const requestedCtx = Number.isFinite(Number(options.num_ctx)) ? Number(options.num_ctx) : 2048;
  const numCtx = Math.max(1024, requestedCtx);
  const timeout = Number.isFinite(Number(options.timeout)) ? Number(options.timeout) : 900000;
  const maxAttempts = Number.isFinite(Number(options.max_attempts)) ? Number(options.max_attempts) : 3;
  const keepAlive = String(options.keep_alive || '30m');
  const formatJson = options.format_json === true;
  const formatSchema = options.format_schema && typeof options.format_schema === 'object'
    ? options.format_schema
    : null;
  const baseUrl = (($env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434').replace(/\/+$/, ''));
  const fallbackModel = String($env.OLLAMA_MODEL_FALLBACK || '').trim();

  async function requestWithModel(modelName) {
    const chatBody = {
      model: modelName,
      stream: false,
      keep_alive: keepAlive,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ],
      options: { temperature, num_predict: numPredict, num_ctx: numCtx },
    };
    if (formatJson) chatBody.format = formatSchema || 'json';

    const data = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/api/chat',
      body: chatBody,
      json: true,
      timeout,
    });
    let text = data?.message?.content || data?.response;
    if (!text || !String(text).trim()) {
      const generateBody = {
        model: modelName,
        stream: false,
        keep_alive: keepAlive,
        prompt: 'System:\n' + systemPrompt + '\n\nUser:\n' + userPrompt,
        options: { temperature, num_predict: numPredict, num_ctx: numCtx },
      };
      if (formatJson) generateBody.format = formatSchema || 'json';

      const generated = await this.helpers.httpRequest({
        method: 'POST',
        url: baseUrl + '/api/generate',
        body: generateBody,
        json: true,
        timeout,
      });
      text = generated?.response;
    }
    if (!text || !String(text).trim()) throw new Error('Ollama response has no content');
    return { text: String(text), model_used: modelName };
  }

  let lastError = null;
  const modelsToTry = [ctx.model_used];
  if (fallbackModel && fallbackModel !== ctx.model_used) modelsToTry.push(fallbackModel);

  for (let modelIndex = 0; modelIndex < modelsToTry.length; modelIndex++) {
    const modelName = modelsToTry[modelIndex];
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        const result = await requestWithModel.call(this, modelName);
        if (modelName !== ctx.model_used) ctx.model_used = modelName;
        return result;
      } catch (error) {
        const details = [error?.message || '', error?.response?.data?.error || ''].filter(Boolean).join(' | ');
        const retryable = /status code\s+5[0-9]{2}|runner process has terminated|llama runner|timed out|socket hang up|econnreset|context canceled|connection reset|no content|response has no content|empty response/i.test(details);
        lastError = details || 'unknown';
        if (retryable && attempt < maxAttempts) {
          await new Promise((resolve) => setTimeout(resolve, 2500 * attempt));
          continue;
        }
        break;
      }
    }
  }

  throw new Error('Ollama call failed after fallback strategy: ' + (lastError || 'unknown'));
}

function parseJsonPayload(rawText) {
  const parsed = extractJsonCandidate(rawText);
  if (typeof parsed === 'string') return extractJsonCandidate(parsed);
  return parsed;
}

async function callOllamaJson(systemPrompt, userPrompt, options = {}) {
  const raw = await callOllamaRaw.call(this, systemPrompt, userPrompt, { ...options, format_json: true });
  try {
    return { parsed: parseJsonPayload(raw.text), raw_text: raw.text, model_used: raw.model_used };
  } catch (parseError) {
    const repairPrompt = [
      'Konvertiere die folgende Antwort in valides JSON.',
      'Wichtig: Antworte nur mit JSON, ohne Markdown, ohne Erklaerungen.',
      options.format_schema ? ('Schema:\n' + JSON.stringify(options.format_schema)) : '',
      'Originalantwort:',
      raw.text,
    ].filter(Boolean).join('\n\n');
    const repaired = await callOllamaRaw.call(
      this,
      'You are a strict JSON formatter. Return valid JSON only.',
      repairPrompt,
      {
        format_json: true,
        format_schema: options.format_schema || null,
        temperature: 0,
        num_predict: Math.max(220, Number.isFinite(Number(options.num_predict)) ? Number(options.num_predict) : 220),
        num_ctx: Math.max(3072, Number.isFinite(Number(options.num_ctx)) ? Number(options.num_ctx) : 3072),
        timeout: Number.isFinite(Number(options.timeout)) ? Number(options.timeout) : 180000,
        max_attempts: 2,
      }
    );
    try {
      return {
        parsed: parseJsonPayload(repaired.text),
        raw_text: raw.text + '\n\n[REPAIRED]\n' + repaired.text,
        model_used: repaired.model_used,
      };
    } catch (repairError) {
      const finalRepairPrompt = [
        'You must output only valid JSON and absolutely nothing else.',
        options.format_schema ? ('Use this schema:\n' + JSON.stringify(options.format_schema)) : '',
        'Reformat this content to strict JSON:',
        repaired.text || raw.text,
      ].filter(Boolean).join('\n\n');
      const strict = await callOllamaRaw.call(
        this,
        'You are a strict JSON transpiler.',
        finalRepairPrompt,
        {
          format_json: true,
          format_schema: options.format_schema || null,
          temperature: 0,
          num_predict: Math.max(260, Number.isFinite(Number(options.num_predict)) ? Number(options.num_predict) : 260),
          num_ctx: Math.max(4096, Number.isFinite(Number(options.num_ctx)) ? Number(options.num_ctx) : 4096),
          timeout: Math.max(240000, Number.isFinite(Number(options.timeout)) ? Number(options.timeout) : 240000),
          max_attempts: 2,
        }
      );
      try {
        return {
          parsed: parseJsonPayload(strict.text),
          raw_text: raw.text + '\n\n[REPAIRED_1]\n' + repaired.text + '\n\n[REPAIRED_2]\n' + strict.text,
          model_used: strict.model_used,
        };
      } catch (strictError) {
        if (typeof options.fallback_json_builder === 'function') {
          try {
            const fallbackParsed = options.fallback_json_builder(raw.text + '\n' + repaired.text + '\n' + strict.text);
            return {
              parsed: fallbackParsed,
              raw_text: raw.text + '\n\n[REPAIRED_1]\n' + repaired.text + '\n\n[REPAIRED_2]\n' + strict.text + '\n\n[FALLBACK_JSON_BUILDER]',
              model_used: strict.model_used,
            };
          } catch (fallbackError) {
            throw new Error('Fallback JSON builder failed: ' + (fallbackError.message || String(fallbackError)));
          }
        }
        throw new Error(
          'JSON parse failed after repair attempt: ' + (strictError.message || String(strictError))
            + ' | raw=' + shortText(raw.text, 180)
            + ' | repaired=' + shortText(repaired.text, 180)
            + ' | strict=' + shortText(strict.text, 180)
        );
      }
    }
  }
}

async function callOllamaText(systemPrompt, userPrompt, options = {}) {
  const raw = await callOllamaRaw.call(this, systemPrompt, userPrompt, options);
  return { text: raw.text, model_used: raw.model_used };
}

async function addStageSummary(step, stage, payload) {
  const summaryPrompt = [
    ctx.prompts.qwen_step_summary,
    'Schritt: ' + step + ' - ' + stage,
    'Payload: ' + shortText(payload, 2500),
    'Antworte nur mit einer kompakten Zusammenfassung.',
  ].join('\n\n');

  let summary = '';
  try {
    const res = await callOllamaText.call(
      this,
      'Du schreibst knappe Workflow-Zusammenfassungen. Keine Markdown-Listen.',
      summaryPrompt,
      { temperature: 0.1, num_predict: 40, num_ctx: 256, timeout: 90000, max_attempts: 2 }
    );
    summary = shortText(res.text.replace(/\s+/g, ' ').trim(), 280);
  } catch (error) {
    summary = 'Zusammenfassung fehlgeschlagen: ' + shortText(error.message || 'unknown', 180);
  }

  ctx.stage_summaries.push({ step, stage, summary });
}

